import{_ as t,o as i,c as a,a3 as o}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"19. Physical Working Conditions","description":"","frontmatter":{"title":"19. Physical Working Conditions","eba":"Medical Specialists 2022-2026","topics":["hours","on-call"]},"headers":[],"relativePath":"ebas/medical-specialists/employment/19-physical-working-conditions.md","filePath":"ebas/medical-specialists/employment/19-physical-working-conditions.md"}'),s={name:"ebas/medical-specialists/employment/19-physical-working-conditions.md"};function n(r,e,c,l,p,d){return i(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="_19-physical-working-conditions" tabindex="-1">19. Physical Working Conditions <a class="header-anchor" href="#_19-physical-working-conditions" aria-label="Permalink to &quot;19. Physical Working Conditions&quot;">​</a></h1><p><strong>19.1</strong> It is agreed that the following infrastructure standards should be met at all Health Services:</p><p><strong>(a)</strong> access to workstations, telecommunication and information technology capable of ensuring administrative and similar work can be accomplished efficiently;</p><p><strong>(b)</strong> 24 hour access to library and all of its resources;</p><p><strong>(c)</strong> reserved car parking paid for by the Health Service and available for a Doctor on on-call and recalled. The parking spaces must be well lit and in a secure place within 200 metres from the front door of the Health Service main entrance;</p><p><strong>(d)</strong> access to Internet and e-mail facilities for work purposes;</p><p><strong>(e)</strong> office available for private discussion with patient’s relatives;</p><p><strong>(f)</strong> access to security escort at night.</p><p><strong>19.2</strong> Where the above is currently not the case, the parties will consult to discuss how quickly the situation can be remedied within available capital funding budgets.</p>',9)])])}const m=t(s,[["render",n]]);export{g as __pageData,m as default};
